/**
 * Tests for sequant_run MCP tool async refactor
 * Issue #388: Replace spawnSync with async spawn
 *
 * Covers:
 * - AC-1: spawn instead of spawnSync
 * - AC-4: Output buffered, truncated to 2000 chars
 * - AC-5: Timeout preserved (30 min default)
 * - AC-6: Tests updated for async
 * - Derived AC-7: Handle ENOENT with descriptive error
 * - Derived AC-8: No orphan processes on timeout/cancel
 */

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import type { ChildProcess } from "child_process";

// Check if MCP SDK is available
const mcpSdkAvailable = await import("@modelcontextprotocol/sdk/server/mcp.js")
  .then(() => true)
  .catch(() => false);

describe.skipIf(!mcpSdkAvailable)("sequant_run tool async refactor", () => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let client: any;
  let cleanup: () => Promise<void>;
  let mockSpawn: ReturnType<typeof vi.fn>;

  beforeEach(async () => {
    // Mock child_process.spawn before importing the tool
    const childProcessModule = await import("child_process");
    mockSpawn = vi.fn();
    vi.doMock("child_process", () => ({
      spawn: mockSpawn,
      spawnSync: childProcessModule.spawnSync, // Keep spawnSync for other uses
    }));

    const { createServer } = await import("../server.js");
    const { Client } =
      await import("@modelcontextprotocol/sdk/client/index.js");
    const { InMemoryTransport } =
      await import("@modelcontextprotocol/sdk/inMemory.js");

    const server = createServer("1.0.0-test");
    const clientInstance = new Client({
      name: "test-client",
      version: "1.0.0",
    });

    const [clientTransport, serverTransport] =
      InMemoryTransport.createLinkedPair();
    await Promise.all([
      clientInstance.connect(clientTransport),
      server.connect(serverTransport),
    ]);

    client = clientInstance;
    cleanup = async () => {
      await clientInstance.close();
      await server.close();
    };
  });

  afterEach(async () => {
    await cleanup();
    vi.doUnmock("child_process");
    vi.clearAllMocks();
  });

  describe("AC-1: spawn instead of spawnSync", () => {
    describe("positive path", () => {
      it("should use child_process.spawn (not spawnSync) and return Promise that resolves after process exit", async () => {
        // Given: A valid issue number array
        const issues = [123];

        // Mock spawn to return a mock ChildProcess
        const mockProcess: Partial<ChildProcess> = {
          on: vi.fn((event: string, handler: Function) => {
            if (event === "exit") {
              // Simulate process exit after handler is registered
              setTimeout(() => handler(0), 10);
            }
            if (event === "error") {
              // No error for this test
            }
            return mockProcess;
          }),
          stdout: {
            on: vi.fn((event: string, handler: Function) => {
              if (event === "data") {
                handler(Buffer.from("success output"));
              }
            }),
          } as any,
          stderr: {
            on: vi.fn((event: string, handler: Function) => {
              if (event === "data") {
                // No stderr for this test
              }
            }),
          } as any,
          kill: vi.fn(),
        };

        mockSpawn.mockReturnValue(mockProcess);

        // When: sequant_run tool handler is called
        const result = await client.callTool({
          name: "sequant_run",
          arguments: { issues },
        });

        // Then: It uses child_process.spawn (not spawnSync), returns a Promise
        expect(mockSpawn).toHaveBeenCalled();
        expect(result).toBeDefined();
        expect(result.content).toHaveLength(1);
      });
    });

    describe("negative path: spawn called with correct arguments", () => {
      it("should call spawn with npx and correct command arguments", async () => {
        throw new Error(
          "Test stub - implement this test: verify spawn() is called with 'npx' and correct args array",
        );
      });
    });
  });

  describe("AC-4: Output buffered, truncated to 2000 chars", () => {
    describe("positive path", () => {
      it("should truncate stdout to last 2000 chars when output exceeds limit", async () => {
        // Given: subprocess emits 5000 chars of stdout
        const largeOutput = "x".repeat(5000);
        const issues = [456];

        const mockProcess: Partial<ChildProcess> = {
          on: vi.fn((event: string, handler: Function) => {
            if (event === "exit") {
              setTimeout(() => handler(0), 10);
            }
            return mockProcess;
          }),
          stdout: {
            on: vi.fn((event: string, handler: Function) => {
              if (event === "data") {
                handler(Buffer.from(largeOutput));
              }
            }),
          } as any,
          stderr: {
            on: vi.fn(),
          } as any,
          kill: vi.fn(),
        };

        mockSpawn.mockReturnValue(mockProcess);

        // When: process exits successfully
        const result = await client.callTool({
          name: "sequant_run",
          arguments: { issues },
        });

        // Then: response.output contains only the last 2000 chars
        expect(result.content).toHaveLength(1);
        const data = JSON.parse(
          (result.content as Array<{ type: string; text: string }>)[0].text,
        );
        expect(data.output).toBeDefined();
        expect(data.output.length).toBeLessThanOrEqual(2000);
        expect(data.output).toBe("x".repeat(2000));
      });
    });

    describe("negative path: small output", () => {
      it("should return full output when it's smaller than 2000 chars", async () => {
        throw new Error(
          "Test stub - implement this test: verify small output is not truncated",
        );
      });
    });

    describe("negative path: empty output", () => {
      it("should handle empty output gracefully", async () => {
        throw new Error(
          "Test stub - implement this test: verify empty output returns empty string",
        );
      });
    });
  });

  describe("AC-5: Timeout preserved (30 min default)", () => {
    describe("positive path: timeout fires", () => {
      it("should send SIGTERM to process when timeout fires and return timeout error", async () => {
        // Given: subprocess has been running longer than timeout
        const issues = [789];
        const TIMEOUT_MS = 1800000; // 30 min default

        const mockProcess: Partial<ChildProcess> = {
          on: vi.fn((event: string, handler: Function) => {
            if (event === "error") {
              // Simulate timeout by emitting error event
              setTimeout(() => handler(new Error("TIMEOUT")), TIMEOUT_MS + 100);
            }
            return mockProcess;
          }),
          stdout: {
            on: vi.fn(),
          } as any,
          stderr: {
            on: vi.fn(),
          } as any,
          kill: vi.fn(),
        };

        mockSpawn.mockReturnValue(mockProcess);

        // When: timeout fires
        const result = await client.callTool({
          name: "sequant_run",
          arguments: { issues },
        });

        // Then: SIGTERM is sent to the process, timeout error is returned
        // Note: timeout implementation should call process.kill()
        expect(result.isError).toBe(true);
        const data = JSON.parse(
          (result.content as Array<{ type: string; text: string }>)[0].text,
        );
        expect(data.error).toBe("EXECUTION_ERROR");
      });
    });

    describe("negative path: timeout not reached", () => {
      it("should complete normally when process exits before timeout", async () => {
        throw new Error(
          "Test stub - implement this test: verify process completes successfully within timeout",
        );
      });
    });
  });

  describe("AC-6: Tests updated for async", () => {
    describe("positive path: valid issue input", () => {
      it("should return success status with valid issue numbers", async () => {
        // Given: existing test scenario - valid input
        const issues = [111];

        const mockProcess: Partial<ChildProcess> = {
          on: vi.fn((event: string, handler: Function) => {
            if (event === "exit") {
              setTimeout(() => handler(0), 10);
            }
            return mockProcess;
          }),
          stdout: {
            on: vi.fn((event: string, handler: Function) => {
              if (event === "data") {
                handler(Buffer.from("test output"));
              }
            }),
          } as any,
          stderr: {
            on: vi.fn(),
          } as any,
          kill: vi.fn(),
        };

        mockSpawn.mockReturnValue(mockProcess);

        // When: run with async spawn mocks
        const result = await client.callTool({
          name: "sequant_run",
          arguments: { issues },
        });

        // Then: all pass (existing test scenario passes)
        expect(result.isError).toBeFalsy();
        expect(result.content).toHaveLength(1);
        const data = JSON.parse(
          (result.content as Array<{ type: string; text: string }>)[0].text,
        );
        expect(data.status).toBe("success");
        expect(data.issues).toEqual(issues);
      });
    });

    describe("negative path: invalid issue input", () => {
      it("should return error for empty issues array with async spawn mocks", async () => {
        // Given: existing test scenario - invalid input
        // When: run with async spawn mocks
        const result = await client.callTool({
          name: "sequant_run",
          arguments: { issues: [] },
        });

        // Then: all pass (existing test scenario passes)
        expect(result.isError).toBe(true);
        const data = JSON.parse(
          (result.content as Array<{ type: string; text: string }>)[0].text,
        );
        expect(data.error).toBe("INVALID_INPUT");
      });
    });

    describe("negative path: non-zero exit code", () => {
      it("should return failure status with non-zero exit code", async () => {
        throw new Error(
          "Test stub - implement this test: verify non-zero exit returns failure status",
        );
      });
    });
  });

  describe("Derived AC-7: Handle ENOENT with descriptive error", () => {
    describe("positive path: ENOENT error handling", () => {
      it("should return EXECUTION_ERROR with descriptive message when spawn emits ENOENT", async () => {
        // Given: spawn emits an 'error' event with code ENOENT
        const issues = [222];

        const mockProcess: Partial<ChildProcess> = {
          on: vi.fn((event: string, handler: Function) => {
            if (event === "error") {
              // Simulate ENOENT error
              const error = new Error("ENOENT: no such file or directory");
              (error as any).code = "ENOENT";
              setTimeout(() => handler(error), 10);
            }
            return mockProcess;
          }),
          stdout: {
            on: vi.fn(),
          } as any,
          stderr: {
            on: vi.fn(),
          } as any,
          kill: vi.fn(),
        };

        mockSpawn.mockReturnValue(mockProcess);

        // When: tool handler processes the error
        const result = await client.callTool({
          name: "sequant_run",
          arguments: { issues },
        });

        // Then: returns EXECUTION_ERROR with descriptive message
        expect(result.isError).toBe(true);
        const data = JSON.parse(
          (result.content as Array<{ type: string; text: string }>)[0].text,
        );
        expect(data.error).toBe("EXECUTION_ERROR");
        expect(data.message).toBeDefined();
      });
    });

    describe("negative path: other spawn errors", () => {
      it("should handle other spawn error codes gracefully", async () => {
        throw new Error(
          "Test stub - implement this test: verify error codes other than ENOENT are handled",
        );
      });
    });
  });

  describe("Derived AC-8: No orphan processes on timeout/cancel", () => {
    describe("positive path: process group kill on timeout", () => {
      it("should kill process and its children when timeout occurs", async () => {
        // Given: subprocess is running
        const issues = [333];

        const mockProcess: Partial<ChildProcess> = {
          pid: 12345,
          on: vi.fn((event: string, handler: Function) => {
            if (event === "error") {
              // Simulate timeout error
              setTimeout(() => handler(new Error("Timeout")), 100);
            }
            return mockProcess;
          }),
          stdout: {
            on: vi.fn(),
          } as any,
          stderr: {
            on: vi.fn(),
          } as any,
          kill: vi.fn(),
        };

        mockSpawn.mockReturnValue(mockProcess);

        // When: timeout or cancellation occurs
        const result = await client.callTool({
          name: "sequant_run",
          arguments: { issues },
        });

        // Then: process and its children are killed (process group kill)
        expect(result.isError).toBe(true);
        // Implementation should call process.kill() with negative PID for process group
        // or use process.kill(-pid) to kill entire process group
      });
    });

    describe("negative path: process cleanup on success", () => {
      it("should properly clean up process resources after successful execution", async () => {
        throw new Error(
          "Test stub - implement this test: verify process resources are cleaned up",
        );
      });
    });

    describe("negative path: process cleanup on error", () => {
      it("should properly clean up process resources when spawn error occurs", async () => {
        throw new Error(
          "Test stub - implement this test: verify process resources are cleaned up on error",
        );
      });
    });
  });

  describe("Integration: tool parameters with async spawn", () => {
    it("should pass phases parameter to spawn command arguments", async () => {
      throw new Error(
        "Test stub - implement this test: verify --phases argument is passed",
      );
    });

    it("should pass qualityLoop parameter to spawn command arguments", async () => {
      throw new Error(
        "Test stub - implement this test: verify --quality-loop argument is passed",
      );
    });

    it("should pass agent parameter to spawn command arguments", async () => {
      throw new Error(
        "Test stub - implement this test: verify --agent argument is passed",
      );
    });

    it("should always include --log-json parameter in spawn command", async () => {
      throw new Error(
        "Test stub - implement this test: verify --log-json is always included",
      );
    });

    it("should set SEQUANT_ORCHESTRATOR=mcp-server in spawn environment", async () => {
      throw new Error(
        "Test stub - implement this test: verify SEQUANT_ORCHESTRATOR env var is set",
      );
    });
  });

  describe("Edge cases", () => {
    it("should handle multiple issue numbers in a single call", async () => {
      throw new Error(
        "Test stub - implement this test: verify multiple issues are passed correctly",
      );
    });

    it("should handle very large issue numbers", async () => {
      throw new Error(
        "Test stub - implement this test: verify large issue numbers don't cause issues",
      );
    });

    it("should handle stderr output separately from stdout", async () => {
      throw new Error(
        "Test stub - implement this test: verify stderr is captured and truncated separately",
      );
    });

    it("should handle mixed stdout and stderr interleaving", async () => {
      throw new Error(
        "Test stub - implement this test: verify interleaved output is handled correctly",
      );
    });
  });
});
